<?php
require 'db.php';
require_login($pdo);
$user = current_user($pdo);
$trees = $pdo->query('SELECT species, latitude, longitude, status, location_label, date_planted FROM trees WHERE latitude IS NOT NULL AND longitude IS NOT NULL')->fetchAll();
?>
<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Map</title><link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"><style>body{margin:0;font-family:Arial,sans-serif;background:#f4f8f3;color:#18311c}.layout{display:grid;grid-template-columns:260px 1fr;min-height:100vh}.side{background:#19261c;color:#eef7ef;padding:22px}.side a{display:block;color:#d9e9d9;padding:11px 12px;border-radius:10px;text-decoration:none;margin-bottom:6px}.side a.active,.side a:hover{background:rgba(255,255,255,.1);color:#fff}.main{padding:24px}.card{background:#fff;border:1px solid #dbe6da;border-radius:16px;padding:18px;box-shadow:0 10px 25px rgba(0,0,0,.05)}#map{height:560px;border-radius:14px;overflow:hidden}@media(max-width:900px){.layout{grid-template-columns:1fr}}</style></head><body><div class="layout"><div class="side"><h2>Tree Keeper</h2><p><?= e($user['full_name']) ?></p><a href="dashboard.php">Dashboard</a><a href="trees.php">Trees</a><a href="add_tree.php">Add Tree</a><a href="tasks.php">Tasks</a><a href="reports.php">Reports</a><a class="active" href="map.php">Map</a><a href="tree_health.php">Health Check</a><a href="profile.php">Profile</a><a href="logout.php">Logout</a></div><div class="main"><h1>Map View</h1><div class="card"><div id="map"></div></div></div></div><script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"></script><script>const trees=<?= json_encode($trees, JSON_UNESCAPED_UNICODE) ?>;const center=trees.length?[parseFloat(trees[0].latitude),parseFloat(trees[0].longitude)]:[-1.286389,36.817223];const map=L.map('map').setView(center,12);L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'&copy; OpenStreetMap contributors'}).addTo(map);trees.forEach(tree=>{L.marker([tree.latitude,tree.longitude]).addTo(map).bindPopup('<strong>'+tree.species+'</strong><br>'+tree.location_label+'<br>Status: '+tree.status.replace('_',' '));});</s